content.query:
union isfuzzy=true
(datatable(d:string)[]),
(let activeUsers = SpyCloudBreachWatchlist_CL
| where TimeGenerated {TimeRange} and severity >= 20
| distinct email;
let remediatedUsers = SpyCloud_ConditionalAccessLogs_CL
| where TimeGenerated {TimeRange}
| distinct UserPrincipalName;
let active = toscalar(activeUsers | summarize count());
let resolved = toscalar(activeUsers | where email in (remediatedUsers) | summarize count());
datatable(Status:string, Count:long)["Active", active - resolved, "Resolved", resolved])

union isfuzzy=true
(datatable(d:string)[]),
(let totalExposed = toscalar(SpyCloudBreachWatchlist_CL | where TimeGenerated > ago(90d) | summarize dcount(email));
let remediated = toscalar(SpyCloud_ConditionalAccessLogs_CL | where TimeGenerated > ago(90d) | summarize dcount(UserPrincipalName));
let criticalOpen = toscalar(SpyCloudBreachWatchlist_CL | where TimeGenerated > ago(7d) | where severity >= 20 | summarize dcount(email));
let avgRemediationHrs = toscalar(SpyCloudBreachWatchlist_CL | where TimeGenerated > ago(90d) | where severity >= 20 | join kind=inner (SpyCloud_ConditionalAccessLogs_CL | where TimeGenerated > ago(90d) | summarize RemTime=min(TimeGenerated) by UserPrincipalName) on $left.email == $right.UserPrincipalName | summarize avg(datetime_diff('hour', RemTime, TimeGenerated)));
let riskScore = case(criticalOpen > 100, 95, criticalOpen > 50, 80, criticalOpen > 20, 60, criticalOpen > 5, 40, 20);
datatable(Metric:string, Value:string, Status:string, Order:int)[
  "Organization Risk Score", tostring(riskScore), iff(riskScore > 70, "HIGH", iff(riskScore > 40, "MEDIUM", "LOW")), 1,
  "Total Exposed Identities (90d)", tostring(totalExposed), iff(totalExposed > 1000, "HIGH", iff(totalExposed > 100, "MEDIUM", "LOW")), 2,
  "Remediation Rate (%)", strcat(tostring(iff(totalExposed > 0, (remediated * 100) / totalExposed, 0)), "%"), iff(remediated * 100 / max_of(totalExposed, 1) > 80, "LOW", "HIGH"), 3,
  "Critical Open Exposures", tostring(criticalOpen), iff(criticalOpen > 20, "HIGH", iff(criticalOpen > 5, "MEDIUM", "LOW")), 4,
  "Avg Remediation Time (hrs)", tostring(round(coalesce(avgRemediationHrs, 0.0), 1)), iff(coalesce(avgRemediationHrs, 0.0) > 48, "HIGH", iff(coalesce(avgRemediationHrs, 0.0) > 24, "MEDIUM", "LOW")), 5
]
| order by Order asc)

union isfuzzy=true
(datatable(d:string)[]),
(let exposed30 = toscalar(SpyCloudBreachWatchlist_CL | where TimeGenerated between(ago(60d) .. ago(30d)) | summarize dcount(email));
let exposed0 = toscalar(SpyCloudBreachWatchlist_CL | where TimeGenerated > ago(30d) | summarize dcount(email));
let remediated30 = toscalar(SpyCloud_ConditionalAccessLogs_CL | where TimeGenerated between(ago(60d) .. ago(30d)) | summarize dcount(UserPrincipalName));
let remediated0 = toscalar(SpyCloud_ConditionalAccessLogs_CL | where TimeGenerated > ago(30d) | summarize dcount(UserPrincipalName));
datatable(Period:string, ExposedUsers:long, RemediatedUsers:long, RemediationRate:string, Trend:string)[
  "Current Month", exposed0, remediated0, strcat(tostring(iff(exposed0 > 0, (remediated0 * 100) / exposed0, 0)), "%"), iff(exposed0 < exposed30, "Improving", "Declining"),
  "Previous Month", exposed30, remediated30, strcat(tostring(iff(exposed30 > 0, (remediated30 * 100) / exposed30, 0)), "%"), ""
])
